+///
+/// Returns a `Cow::Borrowed` if no masking was needed, or `Cow::Owned` if
+/// heredoc content was replaced with placeholder text.
+#[must_use]
+pub fn mask_non_executing_heredocs(command: &str) -> std::borrow::Cow<'_, str> {
+    use std::borrow::Cow;
